import React, { useState } from 'react';

// --- SECTION 1: SMALL CHOPS CURATES ---
const Menu = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const items = [
    { 
      name: "The Starter Pack", 
      price: "7,500", 
      desc: "Samosa, Springroll, Puff-puff, Mosa",
      img: "/images/starter.jpg" 
    },
    { 
      name: "Signature Platter", 
      price: "15,000", 
      desc: "Chicken, Gizz-dodo, Samosa, Springroll",
      img: "/images/signature.jpg"
    },
    { 
      name: "Owambe Special", 
      price: "25,000", 
      desc: "Full variety with extra Peppered Protein",
      img: "/images/owambe.jpg"
    }
  ];

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '30px' }}>
        {items.map((item) => (
          <div key={item.name} style={{ border: `1px solid ${gold}22`, padding: '20px', textAlign: 'center', borderRadius: '4px' }}>
            <img src={item.img} alt={item.name} style={{ width: '100%', height: '200px', objectFit: 'cover', marginBottom: '15px', borderRadius: '2px' }} />
            <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.4rem' }}>{item.name}</h4>
            <p style={{ color: '#555', fontSize: '0.8rem', margin: '15px 0' }}>{item.desc}</p>
            <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.1rem' }}>₦{item.price}</div>
            <button style={{ marginTop: '20px', background: 'none', border: `1px solid ${gold}`, color: gold, padding: '8px 20px', cursor: 'pointer', fontSize: '0.7rem', letterSpacing: '1px' }}>ADD TO BOX</button>
          </div>
        ))}
      </div>

      {/* CUSTOMIZED BOX OPTION */}
      <div style={{ marginTop: '50px', padding: '40px', textAlign: 'center', backgroundColor: '#050505', border: `1px solid ${gold}11` }}>
        <h3 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.6rem' }}>The Customized Box</h3>
        <p style={{ color: '#888', fontSize: '0.9rem', margin: '15px 0' }}>Don't see your perfect combo? Build a box that reflects your unique taste.</p>
        <button style={{ backgroundColor: gold, color: '#000', border: 'none', padding: '12px 30px', fontWeight: 'bold', cursor: 'pointer' }}>START CURATING</button>
      </div>
    </div>
  );
};

export default Menu;

// --- SECTION 2: THE OFFICE LUNCH EXPERIENCE ---
export const Lunch = () => {
  const gold = '#D4AF37';
  const successGreen = '#2ecc71'; 
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const [isClockedIn, setIsClockedIn] = useState(false);

  const timetable = [
    { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad", nutrients: "Complex Carbs + Lean Protein + Fiber" },
    { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread", nutrients: "Sustained Energy + Omega-3s + Carbs" },
    { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain", nutrients: "Iron + Potassium + Essential Minerals" },
    { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies", nutrients: "Vitamin B12 + Antioxidants + Protein" },
    { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)", nutrients: "Dopamine Boost + 100% Organic 😊" }
  ];

  return (
    <div style={{ color: '#fff', padding: '20px', maxWidth: '900px', margin: '0 auto' }}>
      
      {/* WHY LUNCH MATTERS */}
      <section style={{ textAlign: 'center', marginBottom: '60px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, fontSize: '2.5rem', fontStyle: 'italic' }}>Fueling Your Ambition</h3>
        <p style={{ color: '#888', maxWidth: '650px', margin: '20px auto', lineHeight: '1.8' }}>
          As an office worker, your brain consumes 20% of your energy. We provide the fuel to eliminate the 3 PM slump.
        </p>
      </section>

      {/* INTERACTIVE CLOCK-IN */}
      <section style={{ 
        backgroundColor: '#0A0A0A', 
        border: `1.5px solid ${isClockedIn ? successGreen : gold + '33'}`, 
        padding: '40px', borderRadius: '8px', textAlign: 'center', marginBottom: '80px', transition: '0.5s ease'
      }}>
        <h4 style={{ color: isClockedIn ? successGreen : gold, marginBottom: '15px', fontSize: '1.4rem', fontFamily: fancyFont }}>
          {isClockedIn ? "Enjoy Your Meal, Champion! ✅" : "Good Morning, Champion. ✨"}
        </h4>
        <button 
          onClick={() => setIsClockedIn(true)}
          disabled={isClockedIn}
          style={{ 
            backgroundColor: isClockedIn ? successGreen : gold, 
            color: '#000', border: 'none', padding: '12px 40px', fontWeight: 'bold', cursor: isClockedIn ? 'default' : 'pointer'
          }}
        >
          {isClockedIn ? "CLOCKED IN" : "CLOCK IN FOR TODAY'S MEAL"}
        </button>
      </section>

      {/* WEEKLY TIMETABLE */}
      <section style={{ marginBottom: '80px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, textAlign: 'center', marginBottom: '40px' }}>The Weekly Timetable</h3>
        <div style={{ border: `1px solid ${gold}22`, borderRadius: '4px', overflow: 'hidden' }}>
          {timetable.map((item) => (
            <div key={item.day} style={{ padding: '25px', borderBottom: '1px solid #111', backgroundColor: '#050505' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                <span style={{ color: gold, fontWeight: 'bold' }}>{item.day}</span>
                <span style={{ color: '#fff' }}>{item.meal}</span>
              </div>
              <div style={{ fontSize: '0.75rem', color: '#555', fontStyle: 'italic' }}>
                Nutrients: <span style={{ color: '#888' }}>{item.nutrients}</span>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* CUSTOM MENU CTA */}
      <section style={{ textAlign: 'center', marginBottom: '100px', padding: '50px', border: `1px dashed ${gold}33` }}>
        <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.5rem' }}>Prefer a Custom Palette?</h4>
        <p style={{ color: '#666', margin: '15px 0' }}>If you’d like to curate a different timetable, let's build it together.</p>
        <button style={{ background: 'none', border: `1px solid ${gold}`, color: gold, padding: '15px 40px', cursor: 'pointer' }}>
          CURATE MY OWN MENU
        </button>
      </section>

    </div>
  );
};
